INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b4bc9f22-544a-4361-ba8e-8cf7ea0a9b81',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Routing — @RequestMapping, Path Variables, and Controller Prefixing$escape$,
  $escape$Spring Boot routing is handled via `@RequestMapping` and its HTTP-method shortcuts (`@GetMapping`, `@PostMapping`, etc.) on `@RestController` classes. Place `@RequestMapping("/api/v1/users")` at the class level to prefix every handler in that controller — no need to repeat the path segment on each method. Path variables are declared with `{placeholder}` syntax and bound using `@PathVariable`. For optional segments, combine `@PathVariable(required = false)` with a nullable parameter. Query params use `@RequestParam`, which supports `defaultValue` to avoid null checks. To group related controllers under a shared prefix without code duplication, extract the prefix into a constant and reference it in each controller's `@RequestMapping`, or use a common base class annotated with the prefix. Spring MVC resolves routes in registration order for ambiguous patterns — more specific paths (e.g., `/users/me`) should always be declared before wildcard ones (`/users/{id}`). Ant-style wildcards (`/admin/**`) are supported for catch-all routes.$escape$,
  $escape$@RestController
@RequestMapping("/api/v1/users")
public class UserController {

    @GetMapping("/{id}")
    public ResponseEntity<User> getById(@PathVariable Long id) {
        return ResponseEntity.ok(userService.findById(id));
    }

    @GetMapping("/search")
    public List<User> search(
            @RequestParam String query,
            @RequestParam(defaultValue = "10") int limit) {
        return userService.search(query, limit);
    }

    @PostMapping
    public ResponseEntity<User> create(@RequestBody @Valid CreateUserRequest req) {
        return ResponseEntity.status(201).body(userService.create(req));
    }
}$escape$,
  $escape$kotlin$escape$,
