INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cd9bb881-ce61-4f25-9ec6-d30150c6a084',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Filters & Interceptors — Request Pipeline, Global vs Route-Specific, Order Matters$escape$,
  $escape$Spring Boot's request pipeline runs through two middleware layers: Servlet Filters (javax/jakarta.servlet.Filter) and Spring MVC HandlerInterceptors. Filters sit at the Servlet container level — they fire before DispatcherServlet and can short-circuit the request entirely. Interceptors run inside Spring's DispatcherServlet context and have access to the HandlerMethod.

Register a global filter via @Bean or @Component. For route-specific filtering, use FilterRegistrationBean and call setUrlPatterns(). Interceptors are registered in WebMvcConfigurer.addInterceptors() — use addPathPatterns("/api/v1/**") to scope them.

Ordering is explicit: annotate with @Order(1) on filters, or call registration.setOrder(1) on FilterRegistrationBean. Lower values run first. Spring Security's filters (e.g. UsernamePasswordAuthenticationFilter) are wired into the SecurityFilterChain with their own ordered positions — inserting your custom filter before or after them via addFilterBefore()/addFilterAfter() is how you hook into that chain safely.

Use OncePerRequestFilter as your base class to guarantee single execution per request, even across async dispatches.$escape$,
  $escape$@Component
@Order(1)
public class CorrelationIdFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest req,
            HttpServletResponse res, FilterChain chain)
            throws ServletException, IOException {
        String correlationId = Optional
            .ofNullable(req.getHeader("X-Correlation-Id"))
            .orElse(UUID.randomUUID().toString());
        MDC.put("correlationId", correlationId);
        res.setHeader("X-Correlation-Id", correlationId);
        try {
            chain.doFilter(req, res);
        } finally {
            MDC.clear();
        }
    }
}$escape$,
