INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dff02148-539a-4355-b78b-cea1ff366bcf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot JPA — Crushing N+1 with Entity Graphs and Query DSL$escape$,
  $escape$Spring Boot's JPA ecosystem gives you two main query strategies: JPQL/Criteria API (full ORM) and Spring Data JPA's derived queries. The hidden danger is N+1: fetch a list of `Order` entities lazily, then access `order.getItems()` in a loop — Hibernate fires one query per row. Fix it with `@EntityGraph`. Annotate your repository method with `@EntityGraph(attributePaths = {"items", "items.product"})` and Spring Data JPA rewrites the query as a single LEFT JOIN FETCH. For complex dynamic queries, ditch JPQL strings — use QueryDSL or the Criteria API. QueryDSL's `JPAQueryFactory` gives you compile-time safe predicates, IDE completion, and no stringly-typed surprises. For schema migrations, never rely on `spring.jpa.hibernate.ddl-auto=update` in production — that's a data loss waiting to happen. Use Flyway with versioned scripts (`V1__init.sql`) wired via `spring.flyway.enabled=true`. Combine `@Transactional(readOnly = true)` on read methods to hint Hibernate to skip dirty checking, cutting overhead on high-throughput queries.$escape$,
  $escape$@Repository
public interface OrderRepository extends JpaRepository<Order, Long> {

    @EntityGraph(attributePaths = {"items", "items.product"})
    List<Order> findByCustomerId(Long customerId);
}

// QueryDSL dynamic filter
public List<Order> findFiltered(OrderStatus status, LocalDate from) {
    QOrder order = QOrder.order;
    return queryFactory
        .selectFrom(order)
        .where(
            order.status.eq(status),
            order.createdAt.goe(from)
        )
        .fetch();
}$escape$,
  $escape$kotlin$escape$,
