INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '82d40411-7130-4e9e-afe4-62b1b3a6aae1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Input Validation — Schema Enforcement at the Controller Boundary$escape$,
  $escape$Spring Boot's Bean Validation (JSR-380) via `spring-boot-starter-validation` lets you declare constraints directly on DTOs and enforce them at the controller boundary with `@Valid`. Annotate request body fields with `@NotBlank`, `@Size`, `@Email`, `@Pattern`, or `@NotNull` — Spring validates before your method body executes. For custom rules, implement `ConstraintValidator<A, T>` and bind it with a custom annotation. Sanitization is a separate concern: strip HTML with Jsoup or escape with `HtmlUtils.htmlEscape()` before persisting — never rely on validation alone. Error responses need a `@RestControllerAdvice` catching `MethodArgumentNotValidException`; extract field errors from `ex.getBindingResult().getFieldErrors()` and return a structured `ProblemDetail` (Spring 6 native) with `HttpStatus.UNPROCESSABLE_ENTITY`. Avoid `@Valid` on `@PathVariable` or `@RequestParam` directly — use `@Validated` at the class level instead, which triggers method-level constraint proxying via Spring AOP. Always validate at the controller layer, never inside services — services should trust their inputs.$escape$,
  $escape$@RestControllerAdvice
public class ValidationExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ProblemDetail handle(MethodArgumentNotValidException ex) {
        ProblemDetail problem = ProblemDetail
            .forStatusAndDetail(HttpStatus.UNPROCESSABLE_ENTITY, "Validation failed");
        Map<String, String> errors = ex.getBindingResult().getFieldErrors().stream()
            .collect(Collectors.toMap(
                FieldError::getField,
                fe -> Objects.requireNonNullElse(fe.getDefaultMessage(), "invalid")
            ));
        problem.setProperty("errors", errors);
        return problem;
    }
}$escape$,
  $escape$kotlin$escape$,
