INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '416590bf-8837-4618-a57c-c84e35cec79f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot JWT — Stateless Auth with Spring Security 6 Filter Chains$escape$,
  $escape$Spring Security 6 dropped WebSecurityConfigurerAdapter in favor of a bean-based SecurityFilterChain. For JWT, you plug in a custom OncePerRequestFilter that extracts and validates tokens before the UsernamePasswordAuthenticationFilter runs.

The filter calls JwtDecoder (backed by a NimbusJwtDecoder or your own secret-key decoder) to parse and verify the token. On success, wrap the claims in a JwtAuthenticationToken and push it into SecurityContextHolder via UsernamePasswordAuthenticationToken.authenticated(). Spring Security then evaluates @PreAuthorize and method-level security against that context.

Session handling is stateless: set SessionCreationPolicy.STATELESS in the filter chain to prevent Spring from issuing a JSESSIONID cookie. This also means no HttpSession to invalidate on logout — revocation requires either a short-lived token TTL or a Redis-backed token blocklist checked inside your filter.

For role mapping, implement a JwtAuthenticationConverter and override convert() to pull authorities from a custom claim (e.g., roles) rather than the default scope claim. Wire it via oauth2ResourceServer().jwt().jwtAuthenticationConverter(...).$escape$,
  $escape$@Bean
public SecurityFilterChain securityFilterChain(HttpSecurity http, JwtAuthFilter jwtAuthFilter) throws Exception {
    return http
        .csrf(AbstractHttpConfigurer::disable)
        .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
        .authorizeHttpRequests(auth -> auth
            .requestMatchers("/api/auth/**").permitAll()
            .anyRequest().authenticated()
        )
        .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class)
        .build();
}

// Inside JwtAuthFilter extends OncePerRequestFilter
String token = request.getHeader("Authorization").substring(7);
Jwt jwt = jwtDecoder.decode(token);
SecurityContextHolder.getContext().setAuthentication(
    new JwtAuthenticationToken(jwt, authorities)
);$escape$,
  $escape$kotlin$escape$,
