INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c9346f1a-5237-419d-8eee-39618841a033',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot @ControllerAdvice — Global Error Handling Done Right$escape$,
  $escape$@ControllerAdvice + @ExceptionHandler gives you a single place to intercept every exception thrown across all controllers. Pair it with a consistent error response DTO and your API consumers always get a predictable envelope.

Annotate a class with @RestControllerAdvice (shorthand for @ControllerAdvice + @ResponseBody), then declare @ExceptionHandler methods per exception type. Spring MVC routes uncaught exceptions here before they reach the servlet layer.

For validation failures, handle MethodArgumentNotValidException and extract field errors from its BindingResult. For domain-level errors, create a custom hierarchy (e.g., AppException extends RuntimeException) and map subclasses to HTTP status codes via @ResponseStatus or ResponseEntity.

Keep your error envelope consistent: always return the same fields — timestamp, status, error code, message, path — so clients can deserialize without conditional logic. Use ProblemDetail (RFC 9457, native in Spring 6 / Boot 3) instead of rolling your own DTO; it's standardized and HttpEntityMethodProcessor serializes it automatically.

Avoid catching Exception broadly — let specific handlers run first, then fall through to a generic catch-all as a last resort.$escape$,
  $escape$@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    @ResponseStatus(HttpStatus.UNPROCESSABLE_ENTITY)
    public ProblemDetail handleValidation(MethodArgumentNotValidException ex) {
        ProblemDetail pd = ProblemDetail.forStatus(HttpStatus.UNPROCESSABLE_ENTITY);
        pd.setTitle("Validation Failed");
        pd.setProperty("errors", ex.getBindingResult().getFieldErrors()
                .stream()
                .map(f -> f.getField() + ": " + f.getDefaultMessage())
                .toList());
        return pd;
    }

    @ExceptionHandler(ResourceNotFoundException.class)
    public ResponseEntity<ProblemDetail> handleNotFound(ResourceNotFoundException ex, HttpServletRequest req) {
        ProblemDetail pd = ProblemDetail.forStatusAndDetail(HttpStatus.NOT_FOUND, ex.getMessage());
        pd.setInstance(URI.create(req.getRequestURI()));
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(pd);
    }

    @ExceptionHandler(Exception.class)
    @ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR)
    public ProblemDetail handleGeneric(Exception ex) {
        return ProblemDetail.forStatusAndDetail(HttpStatus.INTERNAL_SERVER_ERROR, "Unexpected error");
    }
}$escape$,
  $escape$kotlin$escape$,
