INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5f50b754-7528-49c7-b720-74059e48b099',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Security — CORS, Rate Limiting, Headers, and Injection Prevention$escape$,
  $escape$Spring Boot's `SecurityFilterChain` is your single choke point for hardening HTTP. Configure CORS via `CorsConfigurationSource` — never rely on `@CrossOrigin` annotations in production, as they scatter policy across controllers. For security headers, Spring Security auto-applies `X-Content-Type-Options`, `X-Frame-Options`, and `Cache-Control` when you call `http.headers(withDefaults())`, but you must explicitly add CSP via `headers.contentSecurityPolicy("default-src 'self'")`. Rate limiting isn't built into Spring Security — use Bucket4j with a `HandlerInterceptor` or a `Filter` backed by a Redis token bucket for distributed deployments. For injection prevention, Spring Data JPA parameterizes JPQL automatically, but native queries via `@Query(nativeQuery = true)` require you to bind all parameters with `:param` syntax — never string-interpolate. Additionally, enable `@EnableMethodSecurity` and use `@PreAuthorize` to enforce authorization at the service layer, not just the controller.$escape$,
  $escape$@Bean
SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
    return http
        .cors(cors -> cors.configurationSource(corsConfigurationSource()))
        .headers(headers -> headers
            .contentSecurityPolicy(csp -> csp.policyDirectives("default-src 'self'"))
        )
        .authorizeHttpRequests(auth -> auth
            .requestMatchers("/api/public/**").permitAll()
            .anyRequest().authenticated()
        )
        .sessionManagement(s -> s.sessionCreationPolicy(STATELESS))
        .build();
}

@Bean
CorsConfigurationSource corsConfigurationSource() {
    var config = new CorsConfiguration();
    config.setAllowedOrigins(List.of("https://app.example.com"));
    config.setAllowedMethods(List.of("GET", "POST", "PUT", "DELETE"));
    var source = new UrlBasedCorsConfigurationSource();
    source.registerCorsConfiguration("/api/**", config);
    return source;
}$escape$,
  $escape$kotlin$escape$,
