INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1126eb2d-f1f3-4e54-9782-c4af451f89c1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Performance — HikariCP, Async Handlers, and GZIP in One Pass$escape$,
  $escape$Spring Boot's default HikariCP pool is already fast, but wrong sizing kills throughput. Set `spring.datasource.hikari.maximum-pool-size` to `(core_count * 2) + effective_spindle_count` — not 10. Monitor pool contention via `hikari.pool.Wait` in Micrometer before blindly increasing it.

For async handlers, annotate your `@Configuration` class with `@EnableAsync` and return `CompletableFuture<ResponseEntity<T>>` from `@Async`-annotated service methods. Spring wraps these in a `DeferredResult` under the hood, freeing the Tomcat thread immediately. Pair this with a custom `TaskExecutor` bean to control pool size and queue capacity — the default `SimpleAsyncTaskExecutor` creates unbounded threads.

Response compression is one line: `server.compression.enabled=true`. Add `server.compression.mime-types=application/json,text/html` and `server.compression.min-response-size=2KB` to avoid compressing tiny payloads where CPU cost exceeds savings. For reactive stacks using WebFlux, compression is handled at the Netty codec level automatically when the property is set.$escape$,
  $escape$@Configuration
@EnableAsync
public class AsyncConfig {

    @Bean(name = "taskExecutor")
    public Executor taskExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(Runtime.getRuntime().availableProcessors() * 2);
        executor.setMaxPoolSize(50);
        executor.setQueueCapacity(100);
        executor.setThreadNamePrefix("async-");
        executor.initialize();
        return executor;
    }
}$escape$,
  $escape$kotlin$escape$,
