INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1707feda-3a8e-4e81-b111-3d936720cd67',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Serialization — DTOs, camelCase vs snake_case, and Null Handling$escape$,
  $escape$Spring Boot's Jackson integration gives you precise control over serialization without boilerplate. By default, Jackson serializes field names as-is, but REST APIs often need snake_case for interop with mobile clients or external services. Set `spring.jackson.property-naming-strategy=SNAKE_CASE` globally in `application.properties`, or scope it per class with `@JsonNaming(PropertyNamingStrategies.SnakeCaseStrategy.class)`. For null handling, annotate your response DTO with `@JsonInclude(JsonInclude.Include.NON_NULL)` to strip null fields from the response payload — critical for keeping payloads lean. On request DTOs, add `@JsonIgnoreProperties(ignoreUnknown = true)` to prevent deserialization failures when clients send extra fields. Prefer Java Records for immutable request/response DTOs — Jackson 2.12+ deserializes them natively without a no-arg constructor. Avoid mixing `@JsonProperty` overrides with a global naming strategy; the annotation always wins, creating silent inconsistencies. Keep request and response DTOs separate — sharing them couples your API contract to your internal model and makes versioning painful.$escape$,
  $escape$@JsonNaming(PropertyNamingStrategies.SnakeCaseStrategy.class)
@JsonInclude(JsonInclude.Include.NON_NULL)
public record UserResponse(
    Long userId,
    String displayName,
    String avatarUrl,   // omitted from JSON if null
    Instant createdAt
) {}

@JsonIgnoreProperties(ignoreUnknown = true)
public record CreateUserRequest(
    @NotBlank String displayName,
    String avatarUrl
) {}$escape$,
  $escape$kotlin$escape$,
