INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '639373cb-5f9f-47fb-8c24-9e21bad6ccb4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Structured Logging — Correlation IDs and Request Tracing Done Right$escape$,
  $escape$Spring Boot's default Logback setup logs plain text — fine for humans, painful for log aggregators. Switch to structured JSON using `logstash-logback-encoder` and every log line becomes a queryable event.

For correlation IDs, use a `OncePerRequestFilter`. Generate a UUID per request, store it in MDC via `MDC.put("correlationId", id)`, and propagate it in a response header. Logback automatically includes all MDC keys in structured output — no extra configuration needed.

For request logging, Spring's `CommonsRequestLoggingFilter` is quick but noisy. A custom `OncePerRequestFilter` gives you control: log method, URI, status, and duration using `ContentCachingRequestWrapper`. Pair this with Actuator's `/actuator/httptrace` (renamed to `/actuator/httpexchanges` in Boot 3.x) for in-memory request history.

In `application.yml`, set `logging.pattern.console` to a JSON pattern or rely on `logstash-logback-encoder`'s `LogstashEncoder`. Set `logging.level.web=DEBUG` only in dev — it floods production logs. Use `spring.mvc.log-request-details=true` cautiously; it can leak PII.$escape$,
  $escape$@Component
public class CorrelationIdFilter extends OncePerRequestFilter {
    private static final String CORRELATION_ID = "correlationId";

    @Override
    protected void doFilterInternal(HttpServletRequest req,
            HttpServletResponse res, FilterChain chain)
            throws ServletException, IOException {
        String id = Optional.ofNullable(req.getHeader("X-Correlation-Id"))
                .orElse(UUID.randomUUID().toString());
        MDC.put(CORRELATION_ID, id);
        res.setHeader("X-Correlation-Id", id);
        try {
            chain.doFilter(req, res);
        } finally {
            MDC.remove(CORRELATION_ID); // prevent thread-local leak
        }
    }
}$escape$,
  $escape$kotlin$escape$,
