INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af2ae1d4-ec34-4f17-ae8a-6cf856895a77',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Background Jobs — @Scheduled, TaskExecutor, and Queue Patterns$escape$,
  $escape$Spring Boot offers three tiers for background work. For simple periodic tasks, `@Scheduled` with `@EnableScheduling` is the fastest path — annotate a method with `fixedRate`, `fixedDelay`, or a `cron` expression. Under the hood it uses a single-threaded `ThreadPoolTaskScheduler`; override it with a custom bean to run tasks concurrently. For async one-off work, `@Async` backed by a `ThreadPoolTaskExecutor` decouples callers without infrastructure overhead — set `corePoolSize`, `maxPoolSize`, and `queueCapacity` explicitly or you'll hit `Integer.MAX_VALUE` queue depth in prod. For durable, retryable queues, reach for Spring Batch (chunk-oriented processing with `JobLauncher`) or integrate Spring AMQP with RabbitMQ/SQS via `@RabbitListener`. A common pattern: HTTP endpoint publishes an `ApplicationEvent`, a `@TransactionalEventListener(phase = AFTER_COMMIT)` enqueues the job, and a `@RabbitListener` worker consumes it — guaranteeing the job only enqueues after the DB transaction commits, preventing phantom jobs on rollback.$escape$,
  $escape$@Configuration
@EnableAsync
@EnableScheduling
public class AsyncConfig {
    @Bean(name = "taskExecutor")
    public ThreadPoolTaskExecutor taskExecutor() {
        ThreadPoolTaskExecutor exec = new ThreadPoolTaskExecutor();
        exec.setCorePoolSize(4);
        exec.setMaxPoolSize(16);
        exec.setQueueCapacity(500);
        exec.setThreadNamePrefix("async-worker-");
        exec.setRejectedExecutionHandler(new CallerRunsPolicy());
        exec.initialize();
        return exec;
    }

    @Scheduled(cron = "0 0 * * * *")  // top of every hour
    public void hourlySync() { /* ... */ }
}$escape$,
  $escape$kotlin$escape$,
