INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2ad2dd3e-8dc1-432c-a437-a33deafe002a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spring Boot Actuator — Health Checks, Metrics, and Distributed Tracing in Production$escape$,
  $escape$Spring Boot Actuator exposes production-ready endpoints out of the box. Add `spring-boot-starter-actuator` and you instantly get `/actuator/health`, `/actuator/metrics`, and more. Health indicators auto-detect your beans — DataSource, Redis, RabbitMQ — and aggregate into a single UP/DOWN status. Customize with `@Component` implementing `HealthIndicator` for domain-specific checks.

For metrics, Actuator integrates with Micrometer. Add `micrometer-registry-prometheus` and `/actuator/prometheus` serves a scrape endpoint Prometheus can pull directly. Tag custom metrics with `MeterRegistry` — counters, timers, gauges — all with dimensional labels.

Distributed tracing uses Micrometer Tracing (replaces Spring Cloud Sleuth in Boot 3.x). Add `micrometer-tracing-bridge-otel` plus an exporter like `opentelemetry-exporter-zipkin`. Every inbound HTTP request auto-generates a `traceId`/`spanId` propagated via W3C TraceContext headers. Downstream RestTemplate and WebClient calls carry the context automatically. Configure sampling rate via `management.tracing.sampling.probability=0.1` for 10% in production.$escape$,
  $escape$// application.yml
management:
  endpoints:
    web:
      exposure:
        include: health,metrics,prometheus,info
  endpoint:
    health:
      show-details: always
  tracing:
    sampling:
      probability: 0.1

// Custom HealthIndicator
@Component
public class PaymentServiceHealthIndicator implements HealthIndicator {
    @Override
    public Health health() {
        boolean up = checkPaymentGateway();
        return up ? Health.up().withDetail("gateway", "reachable").build()
                  : Health.down().withDetail("gateway", "unreachable").build();
    }
}$escape$,
